#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define TABLE_SIZE 16
#define MAX_NAME 256

/* Directory entry structure */
typedef struct DirEntry {
 char filename[MAX_NAME];
 int inode;
 struct DirEntry* next;
} DirEntry;

/* Hash table directory structure */
typedef struct {
 DirEntry* table[TABLE_SIZE];
} HashDirectory;

/* Initialize directory */
void init_directory(HashDirectory* dir) {
 for (int i = 0; i < TABLE_SIZE; i++) {
 dir->table[i] = NULL;
 }
}

/* Hash function - simple string hash */
int hash_function(const char* filename) {
 int hash = 0;
 while (*filename) {
 hash = (hash * 31 + *filename) % TABLE_SIZE;
 filename++;
 }
 return hash;
}

/* Search for a file - O(1) average */
int search_file(HashDirectory* dir, const char* filename) {
 int index = hash_function(filename);
 DirEntry* current = dir->table[index];

 while (current != NULL) {
 if (strcmp(current->filename, filename) == 0) {
 return current->inode; /* Found - return inode */
 }
 current = current->next;
 }
 return -1; /* Not found */
}

/* Insert a file - O(1) average */
int insert_file(HashDirectory* dir, const char* filename, int inode) {
 /* Check for duplicate */
 if (search_file(dir, filename) != -1) {
 printf("Error: File '%s' already exists\n", filename);
 return 0;
 }

 int index = hash_function(filename);

 /* Create new entry */
 DirEntry* new_entry = (DirEntry*)malloc(sizeof(DirEntry));
 if (new_entry == NULL) {
 printf("Memory allocation failed\n");
 return 0;
 }

 strncpy(new_entry->filename, filename, MAX_NAME - 1);
 new_entry->filename[MAX_NAME - 1] = '\0';
 new_entry->inode = inode;

 /* Insert at beginning of chain (simple approach) */
 new_entry->next = dir->table[index];
 dir->table[index] = new_entry;

 printf("Inserted: %s -> inode %d at index %d\n", filename, inode, index);
 return 1;
}

/* Delete a file - O(1) average */
int delete_file(HashDirectory* dir, const char* filename) {
 int index = hash_function(filename);
 DirEntry* current = dir->table[index];
 DirEntry* prev = NULL;

 while (current != NULL) {
 if (strcmp(current->filename, filename) == 0) {
 /* Remove from chain */
 if (prev == NULL) {
 dir->table[index] = current->next;
 } else {
 prev->next = current->next;
 }
 free(current);
 printf("Deleted: %s\n", filename);
 return 1;
 }
 prev = current;
 current = current->next;
 }
 printf("File '%s' not found\n", filename);
 return 0;
}

/* List all files - O(n) */
void list_all_files(HashDirectory* dir) {
 printf("\nDirectory contents:\n");
 printf("%-20s %-10s %s\n", "Filename", "Inode", "Hash Index");
 printf("-----------------------------------\n");

 int count = 0;
 for (int i = 0; i < TABLE_SIZE; i++) {
 DirEntry* current = dir->table[i];
 while (current != NULL) {
 printf("%-20s %-10d %d\n", current->filename, current->inode, i);
 count++;
 current = current->next;
 }
 }
 printf("Total files: %d\n", count);
}

/* Display hash table structure */
void show_hash_table(HashDirectory* dir) {
 printf("\nHash Table Structure:\n");
 for (int i = 0; i < TABLE_SIZE; i++) {
 printf("Index %2d: ", i);
 DirEntry* current = dir->table[i];
 if (current == NULL) {
 printf("empty");
 } else {
 while (current != NULL) {
 printf("[%s->%d] ", current->filename, current->inode);
 if (current->next != NULL) printf(" -> ");
 current = current->next;
 }
 }
 printf("\n");
 }
}

/* Free all memory */
void free_directory(HashDirectory* dir) {
 for (int i = 0; i < TABLE_SIZE; i++) {
 DirEntry* current = dir->table[i];
 while (current != NULL) {
 DirEntry* temp = current;
 current = current->next;
 free(temp);
 }
 }
}

int main() {
 HashDirectory dir;
 init_directory(&dir);

 printf("=== Hash Table Directory Implementation ===\n\n");

 /* Insert files */
 insert_file(&dir, "report.txt", 42);
 insert_file(&dir, "main.c", 17);
 insert_file(&dir, "data.csv", 88);
 insert_file(&dir, "image.png", 53);
 insert_file(&dir, "notes.md", 29);
 insert_file(&dir, "readme.txt", 101);

 /* Try duplicate */
 insert_file(&dir, "report.txt", 99);

 /* Search */
 printf("\n=== Search Operations ===\n");
 int result = search_file(&dir, "main.c");
 printf("Search 'main.c': inode = %d\n", result);

 result = search_file(&dir, "missing.txt");
 printf("Search 'missing.txt': inode = %d (not found)\n", result);

 /* List all */
 list_all_files(&dir);

 /* Show hash structure */
 show_hash_table(&dir);

 /* Delete */
 printf("\n=== Delete Operation ===\n");
 delete_file(&dir, "data.csv");
 list_all_files(&dir);

 /* Cleanup */
 free_directory(&dir);

 return 0;
}
